fun solve(nums: Array<Long>): Long {
    var count = 0L
    val n = nums.size
    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val a = nums[i]
            val b = nums[j]
            val absA = Math.abs(a)
            val absB = Math.abs(b)
            val minAb = minOf(absA, absB)
            val maxAb = maxOf(absA, absB)

            val diff = Math.abs(a - b)
            val sumAb = Math.abs(a + b)
            val minDiffSum = minOf(diff, sumAb)
            val maxDiffSum = maxOf(diff, sumAb)

            if (minDiffSum <= minAb && maxDiffSum >= maxAb) {
                count++
            }
        }
    }
    return count
}
